BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?view ?viewName ?viewType WHERE {
  ?pkg vocab:NamedElement_name "TMT-APS-SE" .
  ?pkg vocab:Element_ownedElement ?view .
  ?view rdf:type ?viewType .
  OPTIONAL { ?view vocab:NamedElement_name ?viewName }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?view ?viewName ?viewType WHERE {
  ?pkg vocab:NamedElement_name "TMT-APS-SE" .
  ?pkg vocab:Element_ownedElement+ ?view .
  ?view rdf:type vocab:view .
  OPTIONAL { ?view vocab:NamedElement_name ?viewName }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?type ?name WHERE {
  ?pkg vocab:NamedElement_name "TMT-APS-SE" .
  ?pkg vocab:Element_ownedElement ?elem .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
}
LIMIT 50
